import sys
from collections import deque

class Node:
  def __init__(self, data):
    self.data = data
    self.next = None
    self.prev = None

class Solution:
  def sort(self, head):
    if not head or not head.next:
      return head

    dummy = Node(0)
    dummy.next = head
    prev = dummy

    while head:
      if head.data < prev.data:
        prev.next = head
        head.prev = prev
        prev = head
        head = head.next
      else:
        curr = head
        while curr and curr.data < prev.data:
          prev = curr
          curr = curr.next
        if curr:
          prev.next = head
          head.prev = prev
          head = curr
        else:
          prev.next = head
          head.prev = prev
      head = head.next
    return dummy.next

